code = """import pandas as pd
import json
import re

# Load the filtered reviews by registered users since 2016 with their counts
reviews_by_business_counts = locals()['var_function-call-15748311578621259013']
reviews_df = pd.DataFrame(reviews_by_business_counts)

# Load the business descriptions for these businesses
business_descriptions = locals()['var_function-call-7676406280172481311']
business_description_df = pd.DataFrame(business_descriptions)

# Merge the two dataframes to link review counts with business descriptions
merged_df = pd.merge(reviews_df, business_description_df, on='business_id', how='inner')

# Function to extract categories from the description string
def extract_categories(description):
    categories = []
    # Patterns to match phrases like 'services in X, Y, Z', 'seeking X, Y, Z', or 'offers X, Y, Z'
    patterns = [
        r'services in ([^.]+)',
        r'seeking ([^.]+)',
        r'offers ([^.]+)',
        r'in the fields of ([^.]+)'
    ]
    for pattern in patterns:
        match = re.search(pattern, description, re.IGNORECASE)
        if match:
            # Split by comma and strip whitespace, then extend the categories list
            categories.extend([cat.strip() for cat in match.group(1).split(',') if cat.strip()])
    return categories

# Apply the function to extract categories
merged_df['categories'] = merged_df['description'].apply(extract_categories)

# Explode the categories list to have one category per row
exploded_df = merged_df.explode('categories')

# Group by category and sum the review counts
category_review_counts = exploded_df.groupby('categories')['review_count'].sum().reset_index()

# Sort by review count in descending order and get the top 5
top_5_categories = category_review_counts.sort_values(by='review_count', ascending=False).head(5)

print('__RESULT__:')
print(json.dumps(top_5_categories.to_dict(orient='records')))"""

